let totalAdditions = 0
for (const locale of LOCALES) {
  const filePath = path.join(__dirname, '..', 'messages', `${locale}.json`)
  const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'))
  const article = TRANSLATIONS[locale]
  if (!article) {
    console.warn(`  ${locale.padEnd(3)}  SKIP — no translation defined`)
    continue
  }
  if (!data.brawlerDetail) data.brawlerDetail = {}
  data.brawlerDetail.article = article
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n')
  totalAdditions += Object.keys(article).length
  console.log(`  ${locale.padEnd(3)}  brawlerDetail.article (${Object.keys(article).length} keys)`)
}
console.log(`\n✓ ${LOCALES.length}/${LOCALES.length} locales updated`)
console.log(`  Total: ${totalAdditions} key-additions`)
